#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin — Created: 2026-04-27
# /ork:dev status — inspect lab-stack state. Exit 0 = live, 1 = down/no-state.
# --quiet: suppress output, exit code only (used by boot.sh idempotency check).

set -euo pipefail

QUIET=0
[[ "${1:-}" == "--quiet" ]] && QUIET=1

PROJECT_DIR="${CLAUDE_PROJECT_DIR:-$(pwd)}"
STATE_FILE="${PROJECT_DIR}/.claude/state/dev-stack.json"

if [[ ! -f "${STATE_FILE}" ]]; then
  [[ ${QUIET} -eq 0 ]] && echo "ork:dev — no state file. Run /ork:dev to boot." >&2
  exit 1
fi

# Liveness probe: is at least one tracked PID still running?
any_live=$(python3 - <<'PY'
import json, os, sys
with open(os.environ["STATE_FILE"]) as f:
    state = json.load(f)
live = False
for proc in state.get("processes", {}).values():
    pid = proc.get("pid")
    if isinstance(pid, int) and pid > 0:
        try:
            os.kill(pid, 0)
            live = True
        except (ProcessLookupError, PermissionError):
            pass
print("yes" if live else "no")
PY
)
export STATE_FILE  # required for python heredoc

if [[ "${any_live}" != "yes" ]]; then
  [[ ${QUIET} -eq 0 ]] && echo "ork:dev — state file exists but stack is dead." >&2
  exit 1
fi

if [[ ${QUIET} -eq 1 ]]; then exit 0; fi

# Pretty status
python3 - <<'PY'
import json, os, time
with open(os.environ["STATE_FILE"]) as f:
    s = json.load(f)
print(f"ork:dev — {s.get('branch','?')}")
def alive(pid):
    try: os.kill(pid, 0); return True
    except Exception: return False
for name, proc in s.get("processes", {}).items():
    pid = proc.get("pid", 0)
    cmd = proc.get("command", proc.get("sessionName", ""))
    mark = "✓" if (pid and alive(pid)) or (not pid and "sessionName" in proc) else "✗"
    print(f"  {mark} {name:14} {cmd}")
ems = s.get("emulators") or []
if ems:
    print(f"  emulators: {', '.join(ems)}")
print(f"  base url:  {s.get('baseUrl','?')}")
booted = s.get("bootedAt", "")
if booted:
    print(f"  booted:    {booted}")
PY
